const fs = require('fs');
const path = require('path');
const SKILLS_ROOT = path.join(__dirname, '.agents', 'skills');

// Extract description from each skill's frontmatter
function getDescription(skillPath) {
  const content = fs.readFileSync(skillPath, 'utf8');
  // Try folded block scalar first
  const foldedMatch = content.match(/^description:\s*>-?\s*\n([\s\S]*?)(?=\n\w+:|\n---)/m);
  if (foldedMatch) return foldedMatch[1].replace(/\n\s+/g, ' ').trim();
  const inlineMatch = content.match(/^description:\s*(.+)$/m);
  if (inlineMatch) return inlineMatch[1].trim();
  return '';
}

// Extract keywords from a description
function extractKeywords(desc) {
  const stopWords = new Set(['a','an','the','is','are','was','were','be','been','being','have','has','had','do','does','did','will','would','could','should','may','might','shall','can','need','must','and','or','but','if','then','else','when','where','how','what','which','who','whom','this','that','these','those','it','its','for','from','with','as','at','by','on','in','to','of','not','no','nor','so','yet','both','either','neither','each','every','all','any','few','more','most','other','some','such','than','too','very','just','also','still','even','use','used','using']);
  return desc.toLowerCase()
    .replace(/[^a-z0-9\s-]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 2 && !stopWords.has(w))
    .reduce((acc, w) => { acc[w] = (acc[w] || 0) + 1; return acc; }, {});
}

// Jaccard similarity between two keyword sets
function similarity(a, b) {
  const keysA = new Set(Object.keys(a));
  const keysB = new Set(Object.keys(b));
  const intersection = [...keysA].filter(k => keysB.has(k)).length;
  const union = new Set([...keysA, ...keysB]).size;
  return union > 0 ? intersection / union : 0;
}

const skills = [];
function walk(dir, prefix) {
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    if (!entry.isDirectory()) continue;
    const skillMd = path.join(dir, entry.name, 'SKILL.md');
    if (fs.existsSync(skillMd)) {
      const id = prefix ? prefix + '/' + entry.name : entry.name;
      const desc = getDescription(skillMd);
      skills.push({ id, description: desc, keywords: extractKeywords(desc) });
    } else {
      walk(path.join(dir, entry.name), prefix ? prefix + '/' + entry.name : entry.name);
    }
  }
}
walk(SKILLS_ROOT, '');

// Find collisions (similarity > 0.3)
const collisions = [];
for (let i = 0; i < skills.length; i++) {
  for (let j = i + 1; j < skills.length; j++) {
    const sim = similarity(skills[i].keywords, skills[j].keywords);
    if (sim > 0.3) {
      const shared = Object.keys(skills[i].keywords).filter(k => skills[j].keywords[k]);
      collisions.push({
        skill_a: skills[i].id,
        skill_b: skills[j].id,
        similarity: parseFloat(sim.toFixed(3)),
        shared_keywords: shared.slice(0, 10),
      });
    }
  }
}

collisions.sort((a, b) => b.similarity - a.similarity);

console.log(JSON.stringify({ scanned: skills.length, collisions_above_0_3: collisions.length, collisions }, null, 2));
