import { bus, EVT } from './events';
import { createFloors, ALL_RUNES, STARTER_SPELLS, ALL_SKILLS, defaultTraits } from './data';

const SAVE_KEY = 'escape-dungeon-v11-save';

function createNewPlayer(): PlayerState {
