      selectedIngredients = selectedIngredients.filter(i => i !== id);
      renderScene('forge');
    });
  });

  // Craft button
  document.getElementById('btn-craft')?.addEventListener('click', () => {
    if (selectedIngredients.length >= 2 && recipe) craftSpell();
