    const room = s.floors.find(f => f.id === s.player.currentFloor)?.rooms.find(r => r.id === s.player.currentRoomId);
    if (room) room.cleared = true;
    selectedIngredients = [];
    s.currentScene = 'map';
    saveGame();
    renderScene('map');
  });
});

