      case 'gold':
        s.player.gold += (eff.value || 0);
        if (eff.value) emit('toast', `${eff.value > 0 ? '+' : ''}${eff.value} gold`, eff.value > 0 ? 'success' : 'warning');
        break;
      case 'trait':
        if (eff.traitKey && eff.value) shiftTrait(eff.traitKey, eff.value);
