        ${sp.elements.map(el => `<span class="el-badge" style="background:${elementColor(el)}">${el}</span>`).join('')}
      </div>
    `;
  }).join('');

  // Skill loadout
  const skillSlotsHtml = s.player.skillLoadout.map((slotId, idx) => {
