  color: var(--text-primary);
  cursor: pointer;
  font-size: 14px;
  transition: all 0.15s;
}
.btn:hover { background: var(--bg-hover); transform: translateY(-1px); }
.btn-primary { background: #1565c0; border-color: #1976d2; color: #fff; }
.btn-primary:hover { background: #1976d2; }
.btn-secondary { background: var(--bg-panel); }
.btn-danger { background: #b71c1c; border-color: #c62828; color: #fff; }
.btn-danger:hover { background: #c62828; }
.btn-warning { background: #e65100; border-color: #ef6c00; color: #fff; }
.btn-warning:hover { background: #ef6c00; }
.btn-large { padding: 12px 28px; font-size: 18px; }
.btn-small { padding: 4px 8px; font-size: 12px; }
.btn-dialogue { display: block; width: 100%; text-align: left; margin: 4px 0; padding: 10px 14px; }
.btn-dialogue:hover { background: #2d2d50; border-color: var(--gold); }
.btn.disabled, .btn-disabled { opacity: 0.4; pointer-events: none; }

/* ---- HUD ---- */
.hud {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 100;
  background: linear-gradient(180deg, #0f0e17 0%, #1a1
... [truncated 19430 bytes] ...
t { color: var(--green); }

/* ---- VICTORY ---- */
.victory-scene {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 80vh;
  text-align: center;
}
.victory-content h1 {
  font-size: 32px;
  color: var(--gold);
  margin: 16px 0;
}
.victory-content p { color: var(--text-secondary); margin-bottom: 20px; font-size: 16px; }
.victory-stats { display: flex; flex-wrap: wrap; gap: 12px; justify-content: center; margin-bottom: 24px; }
.victory-stat {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 6px;
  font-size: 14px;
}

/* ---- TOASTS ---- */
#toasts {
  position: fixed;
  bottom: 20px;
  right: 20px;
  z-index: 200;
  display: flex;
  flex-direction: column-reverse;
  gap: 8px;
  pointer-events: none;
}
.toast {
  padding: 8px 14px;
  border-radius: 6px;
  font-size: 13px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  pointer-events: auto;
  display: flex;
  align-items: center;
  gap: 8px;
  animation: slideIn 0.3s ease;
  max-width: 300px;
}
.toast-dismiss {
  background: none;
  border: none;
  color: var(--text-secondary);
  cursor: pointer;
  font-size: 16px;
  margin-left: auto;
}
.toast-info { border-left: 3px solid var(--blue); }
.toast-success { border-left: 3px solid var(--green); }
.toast-warning { border-left: 3px solid var(--orange); }
.toast-danger { border-left: 3px solid var(--red); }
.toast-trait { border-left: 3px solid var(--orange); color: var(--orange); }

@keyframes slideIn {
  from { transform: translateX(100%); opacity: 0; }
  to { transform: translateX(0); opacity: 1; }
}

/* ---- RESPONSIVE ---- */
@media (max-width: 768px) {
  .map-grid { grid-template-columns: repeat(4, 1fr); }
  .combat-arena { flex-direction: column; }
  .combat-vs { padding: 8px 0; }
  .forge-layout, .merchant-layout, .character-layout, .loadout-layout { grid-template-columns: 1fr; }
  .inventory-layout { grid-template-columns: 1fr; }
}

