      set((s) => {
        s.searchQuery = query;
      }),
    setSelectedRunKey: (key) =>
      set((s) => {
        s.selectedRunKey = key;
      }),
    clearAll: () =>
      set((s) => {
        Object.assign(s, INITIAL);
      }),
  }))
);

